5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	export function processScenario(scenario: any): unknown {
16	  const items: Item[] = scenario.steps[0].items;
17	
18	  const basePremium = items.reduce(
19	    (sum, item) => sum + BASE_PREMIUM[item.type],
20	    0,
21	  );
22	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
23	  const premium = basePremium + firstInsurance + PROCESSING_FEE;
24	
25	  return [{ premium }];
26	}
